import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"C++入门教程 Part 1","description":"","frontmatter":{"title":"C++入门教程 Part 1","date":"2024-10-29T16:26:05.000Z","description":"","tags":[],"categories":["C++"]},"headers":[],"relativePath":"posts/20-CPP-入门教程-Part-1.md","filePath":"posts/20-CPP-入门教程-Part-1.md","lastUpdated":1773892556000}'),e={name:"posts/20-CPP-入门教程-Part-1.md"};function n(p,s,o,h,r,d){return i(),t("div",null,[...s[0]||(s[0]=[l(`<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>C++ 是由 Bjarne Stroustrup 在 20 世纪 80 年代初开发的通用编程语言。它是在 C 语言的基础上发展起来的，加入了面向对象编程（OOP）的概念。C++ 作为一门强类型静态语言，以其高效的性能、灵活的功能和广泛的应用领域而著称。</p><p>主要特性包括：</p><ul><li>面向对象编程：支持类与对象、继承、多态等 OOP 特性。</li><li>泛型编程：通过模板机制实现代码重用，提高程序的扩展性。</li><li>低层次内存操控：允许直接操作硬件资源，是开发系统软件、嵌入式系统的理想选择。</li><li>标准库：提供丰富的数据结构、算法和输入输出设施，提升编程效率。</li></ul><p>C++ 常用于开发操作系统、游戏引擎、高性能数据库及实时物联网应用。</p><p>如果以上这些都不能理解也没有关系，跟着本教程的步骤，可以让你对 C++ 有个简单的了解。</p><h2 id="需要什么准备" tabindex="-1">需要什么准备？ <a class="header-anchor" href="#需要什么准备" aria-label="Permalink to &quot;需要什么准备？&quot;">​</a></h2><ol><li>需要一个 Linux 系统的电脑，也可以在虚拟机中安装使用 Linux。</li><li>需要一个文本编辑器，可以是操作系统自带的 gedit 或者任何其他的文本编辑器。本教程推荐使用 VSCode。</li><li>会简单的使用终端输入命令。</li></ol><blockquote><p>如果使用的是 Mac 电脑，可以通过命令<code>xcode-select --install</code>安装必要的开发工具，包括 <code>g++</code></p><p>如果使用的是 Windows10 以上的电脑，建议使用 <code>WSL2</code></p></blockquote><p>建议使用 Linux 学习 C++的理由。</p><ol><li><strong>开放性</strong>：Linux 开源，允许深入操作系统底层。</li><li><strong>开发工具</strong>：提供 GCC、GDB、CMake 等强大工具。</li><li><strong>学习环境</strong>：支持 Shell 脚本和文件系统管理。</li><li><strong>社区支持</strong>：丰富的文档和活跃的社区。</li><li><strong>系统编程</strong>：符合 POSIX 标准，适合跨平台开发。</li><li><strong>实际应用</strong>：广泛用于服务器和嵌入式系统。</li></ol><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><p>这是一个简单的 C++ 程序，用于输出 &quot;Hello, World!&quot;。</p><p>新建一个文件 <code>hello.cpp</code>，输入以下内容：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;iostream&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::cout </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hello, World!&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::endl;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><blockquote><p>可以使用任何文本编辑器，</p></blockquote><p>在终端中输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">g++</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.cpp</span></span></code></pre></div><blockquote><p><code>g++</code> 是 GNU 编译器集合的一部分，用于编译 C++程序。它将 C++源代码转换为可执行文件。通常在 Linux 系统中会预装 GNU 编译器。可以在终端输入 <code>g++ -v</code> 查看系统是否安装了 g++，并查看 g++版本。</p></blockquote><p>在终端中执行生成的可执行文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./hello</span></span></code></pre></div><p>这样，你就可以看到控制台输出：<code>Hello, World!</code>。</p><blockquote><p>输出 &quot;Hello, World!&quot; 是编程中的一个传统，通过这样简单的程序，初学者可以快速了解如何编写和运行代码。</p></blockquote><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>无</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>无</p>`,28)])])}const g=a(e,[["render",n]]);export{k as __pageData,g as default};
